    <button class="primary" @onclick="HandlePlaceOrder">Place Order</button>
</div>

@code {
    [Parameter] public PaymentInfo Payment { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnPlaceOrder { get; set; }

    private string? _errorMessage;

    private async Task HandlePlaceOrder()
    {
        if (string.IsNullOrWhiteSpace(Payment.CardNumber) ||
            string.IsNullOrWhiteSpace(Payment.ExpiryDate))
        {
            _errorMessage = "Card number and expiry date are required.";
            return;
        }

        _errorMessage = null;
        await OnPlaceOrder.InvokeAsync();
    }
}

