@implements IDisposable
@inject IAddressValidator AddressValidator

<fieldset disabled="@_isValidating">
    <legend>Shipping Information</legend>

    <div class="form-group">
        <label for="name">Name</label>
        <input id="name" @bind="Shipping.Name" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="address">Address</label>
        <input id="address" @bind="Shipping.Address" @bind:event="oninput"
               @oninput="OnFieldChanged" />
    </div>

    <div class="form-group">
        <label for="city">City</label>
        <input id="city" @bind="Shipping.City" @bind:event="oninput"
               @oninput="OnFieldChanged" />
    </div>

    <div class="form-group">
        <label for="zip">Zip Code</label>
        <input id="zip" @bind="Shipping.ZipCode" @bind:event="oninput"
               @oninput="OnFieldChanged" />
    </div>
</fieldset>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="validation-error" role="alert">@_errorMessage</div>
}

<button disabled="@_isValidating" @onclick="ValidateAndProceed">
    @if (_isValidating)
    {
        <span class="spinner" aria-hidden="true"></span>
        <span>Validating…</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    [Parameter] public ShippingInfo Shipping { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _errorMessage;

    private void OnFieldChanged(ChangeEventArgs _)
    {
        // User changed an address field — cancel any in-flight validation
        CancelPendingValidation();
        _errorMessage = null;
    }

    private async Task ValidateAndProceed()
    {
        if (string.IsNullOrWhiteSpace(Shipping.Address) ||
            string.IsNullOrWhiteSpace(Shipping.City) ||
            string.IsNullOrWhiteSpace(Shipping.ZipCode))
        {
            _errorMessage = "Address, City, and Zip Code are required.";
            return;
        }

        // Cancel any previous validation before starting a new one
        CancelPendingValidation();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isValidating = true;
        _errorMessage = null;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            // Guard: if cancelled after awaiting, don't touch UI state
            if (token.IsCancellationRequested)
                return;

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _errorMessage = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Expected when the user edits fields or navigates away — no action needed
        }
        finally
        {
            // Only clear the spinner if this is still the active validation
            if (!token.IsCancellationRequested)
            {
                _isValidating = false;
            }
        }
    }

    private void CancelPendingValidation()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _isValidating = false;
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

