@* PaymentStep.razor — collects payment info with Back / Place Order actions *@

<fieldset>
    <legend>Payment Information</legend>

    <div class="form-group">
        <label for="card-number">Card Number</label>
        <input id="card-number" @bind="Payment.CardNumber" />
    </div>

    <div class="form-group">
        <label for="expiry">Expiry Date</label>
        <input id="expiry" placeholder="MM/YY" @bind="Payment.ExpiryDate" />
    </div>
</fieldset>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="validation-error" role="alert">@_errorMessage</div>
}

<div class="button-group">
    <button @onclick="OnBack">Back</button>
    <button class="primary" @onclick="HandlePlaceOrder">Place Order</button>
</div>

@code {
    [Parameter] public PaymentInfo Payment { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnPlaceOrder { get; set; }

    private string? _errorMessage;

    private async Task HandlePlaceOrder()
    {
        if (string.IsNullOrWhiteSpace(Payment.CardNumber) ||
            string.IsNullOrWhiteSpace(Payment.ExpiryDate))
        {
            _errorMessage = "Card number and expiry date are required.";
            return;
        }

        _errorMessage = null;
        await OnPlaceOrder.InvokeAsync();
    }
}

